import React from "react";
import { TrophyIcon, SparklesIcon } from "@heroicons/react/24/outline";
export default function Performance() {
  return (
    <div className="space-y-5 animate-in">
      <div><h1 className="page-title">Performance Management</h1><p className="text-slate-500 text-sm mt-0.5">AI-powered performance reviews and goal tracking</p></div>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="card ai-glow">
          <div className="flex items-center gap-3 mb-4"><div className="w-10 h-10 bg-primary-100 rounded-xl flex items-center justify-center"><SparklesIcon className="w-5 h-5 text-primary-600" /></div><div><h3 className="font-semibold text-slate-900">AI Review Generator</h3><p className="text-xs text-slate-500">Generate reviews using GPT-4</p></div></div>
          <p className="text-sm text-slate-600 mb-4">Input KPIs, manager notes, and peer feedback — AI writes a professional performance review.</p>
          <button className="btn-primary w-full"><SparklesIcon className="w-4 h-4" />Generate Review</button>
        </div>
        <div className="card">
          <div className="flex items-center gap-3 mb-4"><div className="w-10 h-10 bg-amber-100 rounded-xl flex items-center justify-center"><TrophyIcon className="w-5 h-5 text-amber-600" /></div><div><h3 className="font-semibold text-slate-900">Performance Cycles</h3><p className="text-xs text-slate-500">Manage review periods</p></div></div>
          <div className="space-y-3 text-sm">{[{cycle:"Q4 2024 Review",status:"In Progress",due:"Dec 31, 2024"},{cycle:"Annual 2025",status:"Not Started",due:"Jan 15, 2025"}].map(c => (
            <div key={c.cycle} className="flex justify-between items-center py-2 border-b border-slate-100 last:border-0"><div><p className="font-medium text-slate-800">{c.cycle}</p><p className="text-xs text-slate-400">Due {c.due}</p></div><span className={`badge ${c.status==="In Progress"?"badge-warning":"badge-neutral"}`}>{c.status}</span></div>
          ))}</div>
        </div>
      </div>
    </div>
  );
}
